import "../index.css";
import projects from '../projects';
import { Link, useLocation, useParams, matchPath } from "react-router-dom";
import ReactMarkdown from 'react-markdown';
import React, { useEffect, useState } from "react";

function GetProject() {
  const params = useParams();

  return params["project"];
}

const PageComponent = ()=> {
  var project = GetProject();

  var file = projects.filter(({ name }) => name == project)[0].file;

  let [ content, setContent] = useState({md: ""});

  useEffect(()=> {
      fetch(file)
          .then((res) => res.text())
          .then((md) => {
              setContent({ md })
          })
  }, [])

  return (
    <div className="post">
      <ReactMarkdown children={content.md}/>
    </div>
  )
}

const ProjectSubPage = ({project = ""}) => (
  <div className="main">
    <h1>
      {GetProject()}
    </h1>
    <PageComponent />
  </div>
)

export default ProjectSubPage;
